// Normalization & Scoring Layer
const items = $input.all();
const normalizedItems = [];

for (const item of items) {
  const d = item.json;

  const spend = parseFloat(d.spend) || 0;
  const clicks = parseFloat(d.clicks) || 0;
  const conversions = parseFloat(d.conversions) || 0;
  const revenue = parseFloat(d.revenue) || 0;
  const cpc = parseFloat(d.cpc) || 0;
  const ctr = parseFloat(d.ctr) || 0;
  const roas = parseFloat(d.roas) || (spend > 0 ? revenue / spend : 0);

  // Derived Metrics
  const cost_per_conversion = conversions > 0 ? spend / conversions : 0;
  const profit = revenue - spend;

  // Performance Score (0-100)
  // ROAS weight: 60%, CTR weight: 40%
  const roas_score = Math.min((roas / 6) * 60, 60);
  const ctr_score = Math.min((ctr / 5) * 40, 40);
  const performance_score = Math.round(roas_score + ctr_score);

  // Campaign Grade
  let grade;
  if (roas > 4) grade = 'A';
  else if (roas >= 2) grade = 'B';
  else grade = 'C';

  // Simulated previous period CPC (±20% variation for demo)
  const prev_cpc = cpc * (0.85 + Math.random() * 0.3);
  const cpc_increase_pct = prev_cpc > 0 ? ((cpc - prev_cpc) / prev_cpc) * 100 : 0;

  // Simulated previous period spend & conversions
  const prev_spend = spend * (0.8 + Math.random() * 0.3);
  const prev_conversions = conversions * (0.9 + Math.random() * 0.3);
  const spend_increase_pct = prev_spend > 0 ? ((spend - prev_spend) / prev_spend) * 100 : 0;
  const conversion_growth_pct = prev_conversions > 0 ? ((conversions - prev_conversions) / prev_conversions) * 100 : 0;

  normalizedItems.push({
    json: {
      source: d.source,
      client_name: d.client_name,
      campaign_name: d.campaign_name,
      spend,
      clicks,
      conversions,
      revenue,
      cpc,
      ctr,
      roas,
      cost_per_conversion: parseFloat(cost_per_conversion.toFixed(2)),
      profit: parseFloat(profit.toFixed(2)),
      performance_score,
      grade,
      prev_cpc: parseFloat(prev_cpc.toFixed(2)),
      cpc_increase_pct: parseFloat(cpc_increase_pct.toFixed(2)),
      prev_spend: parseFloat(prev_spend.toFixed(2)),
      spend_increase_pct: parseFloat(spend_increase_pct.toFixed(2)),
      conversion_growth_pct: parseFloat(conversion_growth_pct.toFixed(2)),
      timestamp: new Date().toISOString()
    }
  });
}

return normalizedItems;

const d = $json;
const anomalies = [];
let risk_reason = '';
let suggested_action = '';

if (d.cpc_increase_pct > 30) {
  anomalies.push('CPC spike of ' + d.cpc_increase_pct.toFixed(1) + '%');
  suggested_action += 'Review bidding strategy and keyword targeting. ';
}
if (d.roas < 2) {
  anomalies.push('ROAS critically low at ' + d.roas.toFixed(2));
  suggested_action += 'Pause underperforming ad sets. Reallocate budget to top performers. ';
}
if (d.spend_increase_pct > 40 && d.conversion_growth_pct < 5) {
  anomalies.push('Spend up ' + d.spend_increase_pct.toFixed(1) + '% with only ' + d.conversion_growth_pct.toFixed(1) + '% conversion growth');
  suggested_action += 'Audit audience targeting and landing page conversion rate. ';
}
if (d.grade === 'C') {
  anomalies.push('Grade C campaign — ROAS below acceptable threshold');
  suggested_action += 'Consider campaign restructure or temporary pause pending review. ';
}

risk_reason = anomalies.join('; ');

return [{
  json: {
    ...d,
    anomalies,
    risk_reason,
    suggested_action: suggested_action.trim(),
    is_at_risk: anomalies.length > 0
  }
}];

