const d = $json;

const roas_trend = d.roas < 2 ? 'critically low' : d.roas < 3 ? 'below target' : d.roas < 5 ? 'acceptable' : 'strong';
const cpc_trend = d.cpc_increase_pct > 30 ? 'a sharp increase of ' + d.cpc_increase_pct.toFixed(1) + '%' : d.cpc_increase_pct > 10 ? 'a moderate increase of ' + d.cpc_increase_pct.toFixed(1) + '%' : 'stable performance';
const conv_status = d.conversion_growth_pct < 0 ? 'declining conversions' : d.conversion_growth_pct < 5 ? 'stagnant conversion growth' : 'improving conversions';
const profit_status = d.profit > 0 ? 'generating $' + d.profit.toFixed(2) + ' in profit' : 'operating at a loss of $' + Math.abs(d.profit).toFixed(2);

let executive_summary = `EXECUTIVE PERFORMANCE REPORT — ${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}\n\n`;
executive_summary += `CLIENT: ${d.client_name}\n`;
executive_summary += `CAMPAIGN: ${d.campaign_name} (${d.source.toUpperCase()})\n`;
executive_summary += `OVERALL GRADE: ${d.grade} | PERFORMANCE SCORE: ${d.performance_score}/100\n\n`;
executive_summary += `SUMMARY:\n`;
executive_summary += `${d.client_name}'s campaign "${d.campaign_name}" is currently ${roas_trend} with a ROAS of ${d.roas.toFixed(2)}, `;
executive_summary += `showing ${cpc_trend} in cost-per-click and ${conv_status}. `;
executive_summary += `The campaign is ${profit_status} on $${d.spend.toFixed(2)} in total spend.\n\n`;

if (d.is_at_risk) {
  executive_summary += `RISK FLAGS:\n${d.risk_reason}\n\n`;
  executive_summary += `RECOMMENDED ACTIONS:\n${d.suggested_action}\n\n`;
} else {
  executive_summary += `STATUS: Campaign is performing within acceptable parameters. Continue monitoring.\n\n`;
}

executive_summary += `KEY METRICS:\n`;
executive_summary += `• Spend: $${d.spend.toFixed(2)} | Revenue: $${d.revenue.toFixed(2)} | Profit: $${d.profit.toFixed(2)}\n`;
executive_summary += `• ROAS: ${d.roas.toFixed(2)} | CPC: $${d.cpc.toFixed(2)} | CTR: ${d.ctr.toFixed(2)}%\n`;
executive_summary += `• Conversions: ${d.conversions} | Cost/Conv: $${d.cost_per_conversion.toFixed(2)}\n`;
executive_summary += `• Performance Score: ${d.performance_score}/100`;

return [{
  json: {
    ...d,
    executive_summary
  }
}];
